const url = $input.first().json.body.url;
const keyword = ($input.first().json.body.keyword || '').trim();
const browserlessToken = $input.first().json.body.browserless_token || '';
return [{ json: { url, keyword, browserlessToken, useBrowserless: browserlessToken.length > 0 } }];

// Get HTML from whichever fetch method ran
const raw = $input.first().json;
let html = '';
if (typeof raw === 'string') html = raw;
else if (raw.data) html = raw.data;
else if (raw.body) html = raw.body;
else html = JSON.stringify(raw);

const url = $('Prepare').first().json.url;
const keyword = ($('Prepare').first().json.keyword || '').toLowerCase().trim();

function strip(s){return(s||'').replace(/<[^>]+>/g,' ').replace(/&[a-z]+;/g,' ').replace(/\s+/g,' ').trim();}

// === METADATA ===
let title='';const tm=html.match(/<title[^>]*>(.*?)<\/title>/si);if(tm)title=strip(tm[1]);
let metaDesc='';let m=html.match(/<meta[^>]+name\s*=\s*["']description["'][^>]*content\s*=\s*["']([^"']*)["']/i);if(m)metaDesc=m[1];if(!metaDesc){m=html.match(/<meta[^>]+content\s*=\s*["']([^"']*)["'][^>]*name\s*=\s*["']description["']/i);if(m)metaDesc=m[1];}
let ogTitle='';m=html.match(/<meta[^>]+property\s*=\s*["']og:title["'][^>]*content\s*=\s*["']([^"']*)["']/i);if(m)ogTitle=m[1];
let ogDesc='';m=html.match(/<meta[^>]+property\s*=\s*["']og:description["'][^>]*content\s*=\s*["']([^"']*)["']/i);if(m)ogDesc=m[1];
let canonical='';m=html.match(/<link[^>]+rel\s*=\s*["']canonical["'][^>]*href\s*=\s*["']([^"']+)["']/i);if(m)canonical=m[1];
let robots='index, follow';m=html.match(/<meta[^>]+name\s*=\s*["']robots["'][^>]*content\s*=\s*["']([^"']*)["']/i);if(m)robots=m[1];
const schemaTypes=[...new Set((html.match(/"@type"\s*:\s*"([^"]+)"/gi)||[]).map(s=>{const x=s.match(/"([^"]+)"$/);return x?x[1]:'';}).filter(Boolean))];

// === CONTENT ===
let content=html.replace(/<(script|style|svg|template|iframe|noscript)[^>]*>[\s\S]*?<\/\1>/gi,' ');
let body2=content;const bm2=content.match(/<body[^>]*>([\s\S]*)<\/body>/i);if(bm2)body2=bm2[1];
body2=body2.replace(/<(nav|footer|header|aside|form)[^>]*>[\s\S]*?<\/\1>/gi,' ');
let mc='';const sels=[/<main[^>]*>([\s\S]*?)<\/main>/i,/<article[^>]*>([\s\S]*?)<\/article>/i,/<div[^>]*class\s*=\s*["'][^"']*entry-content[^"']*["'][^>]*>([\s\S]*?)<\/div>/i];
for(const s of sels){const sm=body2.match(s);if(sm&&strip(sm[1]).split(/\s+/).length>=30){mc=sm[1];break;}}
if(!mc){const hm2=body2.match(/<h[12]\b[^>]*>([\s\S]*)/i);if(hm2)mc=hm2[1];}
if(!mc)mc=body2;
const text=strip(mc);const words=text.split(/\s+/).filter(w=>w.length>0);const wordCount=words.length;

// === HEADINGS ===
const h1s=(html.match(/<h1[^>]*>(.*?)<\/h1>/gi)||[]).map(h=>strip(h)).filter(Boolean);
const h2s=(html.match(/<h2[^>]*>(.*?)<\/h2>/gi)||[]).map(h=>strip(h)).filter(Boolean);
const h3s=(html.match(/<h3[^>]*>(.*?)<\/h3>/gi)||[]).map(h=>strip(h)).filter(Boolean);

// === IMAGES/LINKS/MISC ===
const imgs=html.match(/<img\b[^>]*>/gi)||[];let noAlt=0;imgs.forEach(t=>{if(!/alt\s*=\s*["'][^"']+["']/i.test(t))noAlt++;});
const host=(()=>{try{return new URL(url).hostname;}catch(e){return'';}})();
const anchors=html.match(/<a\s[^>]*href\s*=\s*["']([^"'#]+)["'][^>]*>/gi)||[];
let intL=0,extL=0;anchors.forEach(a=>{const hm3=a.match(/href\s*=\s*["']([^"'#]+)["']/i);if(!hm3)return;const h2=hm3[1];if(h2.startsWith('/')||h2.includes(host))intL++;else if(h2.startsWith('http'))extL++;});
const paragraphs=(html.match(/<p\b[^>]*>/gi)||[]).length;
const tables=(html.match(/<table\b/gi)||[]).length;
const videos=(html.match(/<(video|iframe)[^>]*(youtube|vimeo|aparat|mp4|embed)/gi)||[]).length;
const hasFaq=/سوالات متداول|FAQ|faq-section|FAQPage/i.test(html);
const hasToc=/table.of.content|فهرست مطالب|ez-toc|lwptoc/i.test(html);
const hasBreadcrumb=/breadcrumb|BreadcrumbList/i.test(html);

// === TOP KEYWORDS ===
const stops=['و','در','به','از','که','این','را','با','است','برای','آن','یک','تا','هم','ها','یا','شده','می','بر','the','is','a','of','to','in'];
const wL=text.toLowerCase().split(/[\s\u200C,.;:!?()\[\]\/]+/).filter(w=>w.length>2&&!stops.includes(w)&&!/^\d+$/.test(w));
const freq={};wL.forEach(w=>freq[w]=(freq[w]||0)+1);
const topKw=Object.entries(freq).sort((a,b)=>b[1]-a[1]).slice(0,12).map(([word,count])=>({word,count}));

// === KEYWORD ANALYSIS ===
let kwA={};if(keyword){const kl=keyword;const tl=title.toLowerCase();const inT=tl.includes(kl)?1:0;const inH1=h1s.some(h=>h.toLowerCase().includes(kl))?1:0;const inH2=h2s.some(h=>h.toLowerCase().includes(kl))?1:0;const inM=metaDesc.toLowerCase().includes(kl)?1:0;const inU=url.toLowerCase().includes(kl)?1:0;const kc=(text.toLowerCase().split(kl).length-1);const dens=wordCount>0?Math.round((kc/wordCount)*10000)/100:0;const prom=Math.min(100,(inT?25:0)+(inH1?20:0)+(inH2?10:0)+(inM?15:0)+(inU?15:0)+Math.min(15,Math.round(dens*5)));kwA={in_title:inT,in_h1:inH1,in_h2:inH2,in_meta:inM,in_url:inU,density:dens,prominence:prom,count:kc};}

// === STRENGTHS/WEAKNESSES ===
const str=[];const wk=[];
if(wordCount>=1500)str.push('محتوای جامع ('+wordCount+' کلمه)');else if(wordCount<300)wk.push('محتوا کوتاه ('+wordCount+')');
if(h2s.length>=3)str.push('ساختار هدینگ خوب');else if(h2s.length<2)wk.push('هدینگ H2 کم');
if(imgs.length>=3)str.push('تصاویر مناسب');else if(imgs.length<2)wk.push('تصاویر کم');
if(noAlt>0)wk.push(noAlt+' تصویر بدون alt');
if(tables>0)str.push('جدول دارد');else wk.push('جدول ندارد');
if(hasFaq)str.push('FAQ دارد');else wk.push('FAQ ندارد');
if(videos>0)str.push('ویدیو دارد');
if(schemaTypes.length>0)str.push('Schema: '+schemaTypes.join(', '));else wk.push('Schema ندارد');
if(intL>=5)str.push('لینک داخلی قوی ('+intL+')');else if(intL<3)wk.push('لینک داخلی کم');
if(keyword){if(kwA.in_title)str.push('کلمه در عنوان ✓');else wk.push('کلمه در عنوان نیست');if(kwA.density>=0.5&&kwA.density<=2.5)str.push('تراکم مناسب');else if(kwA.density<0.5)wk.push('تراکم کم');}

let score=Math.min(100,Math.round(wordCount/50)+h2s.length*3+imgs.length*2+(h1s.length>=1?10:0)+(tables>0?5:0)+(hasFaq?10:0)+(schemaTypes.length>0?8:0));

return[{json:{url,word_count:wordCount,h1:h1s.length,h2:h2s.length,h3:h3s.length,h1_texts:h1s.slice(0,3),h2_texts:h2s.slice(0,15),h3_texts:h3s.slice(0,5),images:imgs.length,images_no_alt:noAlt,internal_links:intL,external_links:extL,title,meta_desc:metaDesc,og_title:ogTitle,og_description:ogDesc,canonical_url:canonical,robots_meta:robots,schema:schemaTypes,paragraphs,tables,videos,has_faq:hasFaq?1:0,has_video:videos>0?1:0,has_table:tables>0?1:0,has_toc:hasToc?1:0,has_breadcrumb:hasBreadcrumb?1:0,content_type:wordCount>300?'article':'-',reading_level:0,keyword_density:kwA.density||0,top_keywords:topKw,word_count_score:score,keyword_analysis:kwA,response_time:0,strengths:str,weaknesses:wk,section_words:[],note:wordCount<50&&html.length>10000?'صفحه JS-rendered — Browserless توصیه می‌شود.':''}}];
